package main

import (
    "context"
    "fmt"
    "runtime"
    "time"
)

func main() {
    // ---- Goroutine leak example ----
    fmt.Println("=== Goroutine Leak ===")

    // ---- Leaking goroutine ----
    fmt.Println("Before leak:", runtime.NumGoroutine())

    // This goroutine never exits
    go func() {
        for {
            time.Sleep(time.Second)
        }
    }()

    time.Sleep(100 * time.Millisecond)
    fmt.Println("After leak:", runtime.NumGoroutine())

    // ---- Fixed with context ----
    fmt.Println("\n=== Fixed with Context ===")

    ctx, cancel := context.WithCancel(context.Background())

    go func() {
        for {
            select {
            case <-ctx.Done():
                return
            default:
                time.Sleep(100 * time.Millisecond)
            }
        }
    }()

    time.Sleep(50 * time.Millisecond)
    fmt.Println("Before cancel:", runtime.NumGoroutine())
    cancel()
    time.Sleep(50 * time.Millisecond)
    fmt.Println("After cancel:", runtime.NumGoroutine())

    // ---- Leak from channel ----
    fmt.Println("\n=== Channel Leak ===")

    ch := make(chan int)

    go func() {
        // Blocks forever waiting for a value
        v := <-ch
        fmt.Println("Received:", v)
    }()

    time.Sleep(50 * time.Millisecond)
    fmt.Println("Channel leak:", runtime.NumGoroutine())
    // ch <- 42  // Uncomment to fix

    // ---- Fixed with timeout ----
    fmt.Println("\n=== Fixed with Timeout ===")

    ch2 := make(chan int)

    go func() {
        select {
        case v := <-ch2:
            fmt.Println("Received:", v)
        case <-time.After(100 * time.Millisecond):
            fmt.Println("Timeout, returning")
        }
    }()

    time.Sleep(150 * time.Millisecond)
    fmt.Println("After timeout:", runtime.NumGoroutine())
}

