    // Leaking goroutine
    go func() {
        for {
            fmt.Println("Leaking...")
            time.Sleep(100 * time.Millisecond)
        }
    }()

    // Program exits but goroutine keeps running
    time.Sleep(200 * time.Millisecond)
    fmt.Println("Main exits")
}

phase2.explanation:
The goroutine runs forever, leaking resources.

**The fix:**
```go
ctx, cancel := context.WithCancel(context.Background())
defer cancel()

go func() {
    for {
        select {
        case <-ctx.Done():
            return
        default:
            fmt.Println("Not leaking")
            time.Sleep(100 * time.Millisecond)
        }
    }
}()
```

**Go-chan says:**
"Every goroutine should have a way to exit."

phase3.solution:
package main

import (
    "context"
    "fmt"
    "runtime"
    "time"
)

func main() {
    fmt.Println("Before:", runtime.NumGoroutine())

    ctx, cancel := context.WithCancel(context.Background())

    go func() {
        for {
            select {
            case <-ctx.Done():
                return
            default:
                fmt.Println("Working...")
                time.Sleep(100 * time.Millisecond)
            }
        }
    }()

    time.Sleep(300 * time.Millisecond)
    cancel()
    time.Sleep(50 * time.Millisecond)

    fmt.Println("After:", runtime.NumGoroutine())
}
